import{_ as r,o as t,c as s,ai as o}from"./chunks/framework.LYGRWSbL.js";const g=JSON.parse('{"title":"Module 2 - Construire une phrase","description":"","frontmatter":{"prev":{"text":"Module 1 - Le pluriel","link":"../module-1-le-pluriel/"}},"headers":[],"relativePath":"module-2-construire-une-phrase/index.md","filePath":"module-2-construire-une-phrase/index.md","lastUpdated":1773303592000}'),n={name:"module-2-construire-une-phrase/index.md"};function a(i,e,l,d,u,c){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="module-2-construire-une-phrase" tabindex="-1">Module 2 - Construire une phrase <a class="header-anchor" href="#module-2-construire-une-phrase" aria-label="Permalink to “Module 2 - Construire une phrase”">​</a></h1><p><strong>Prérequis :</strong> <a href="./../module-1-fondations/">Module 1 - Les fondations</a></p><p><strong>Objectif :</strong> formuler des phrases simples et correctes en allemand, comprendre l&#39;ordre des mots et conjuguer au présent.</p><p>Tu sais te présenter et prononcer l&#39;allemand. Maintenant on construit des phrases. Ce module introduit la grammaire de base, mais toujours au service de l&#39;expression, pas pour elle-même.</p><div class="info custom-block"><p class="custom-block-title">Ce module introduit les cas grammaticaux</p><p>L&#39;allemand possede 4 cas qui changent la forme des articles. Ce module couvre le premier, le nominatif. Les autres (accusatif, datif, genitif) arrivent progressivement dans les modules suivants.</p></div><h2 id="au-programme" tabindex="-1">Au programme <a class="header-anchor" href="#au-programme" aria-label="Permalink to “Au programme”">​</a></h2><div class="mt-6 grid gap-3"><a href="./ordre-des-mots" class="group flex items-start gap-5 p-5 rounded-xl border border-gray-200 hover:border-green-500 hover:shadow-md transition-all duration-200 no-underline"><span class="text-3xl font-black text-gray-300 group-hover:text-green-200 transition-colors select-none w-8 text-center shrink-0">1</span><div class="min-w-0"><div class="font-semibold text-gray-900 group-hover:text-green-600 transition-colors">L&#39;ordre des mots</div><div class="text-sm text-gray-500 mt-1">La règle fondamentale : le verbe est toujours en deuxième position.</div></div><span class="ml-auto text-gray-300 group-hover:text-green-400 transition-colors shrink-0">→</span></a><a href="./nominatif" class="group flex items-start gap-5 p-5 rounded-xl border border-gray-200 hover:border-green-500 hover:shadow-md transition-all duration-200 no-underline"><span class="text-3xl font-black text-gray-300 group-hover:text-green-200 transition-colors select-none w-8 text-center shrink-0">2</span><div class="min-w-0"><div class="font-semibold text-gray-900 group-hover:text-green-600 transition-colors">Le nominatif</div><div class="text-sm text-gray-500 mt-1">Le premier cas - celui du sujet de la phrase.</div></div><span class="ml-auto text-gray-300 group-hover:text-green-400 transition-colors shrink-0">→</span></a><a href="./present-verbes-reguliers" class="group flex items-start gap-5 p-5 rounded-xl border border-gray-200 hover:border-green-500 hover:shadow-md transition-all duration-200 no-underline"><span class="text-3xl font-black text-gray-300 group-hover:text-green-200 transition-colors select-none w-8 text-center shrink-0">3</span><div class="min-w-0"><div class="font-semibold text-gray-900 group-hover:text-green-600 transition-colors">Le présent - verbes réguliers</div><div class="text-sm text-gray-500 mt-1">Conjuguer machen, spielen, lernen et tous les verbes en -en.</div></div><span class="ml-auto text-gray-300 group-hover:text-green-400 transition-colors shrink-0">→</span></a><a href="./verbes-irreguliers" class="group flex items-start gap-5 p-5 rounded-xl border border-gray-200 hover:border-green-500 hover:shadow-md transition-all duration-200 no-underline"><span class="text-3xl font-black text-gray-300 group-hover:text-green-200 transition-colors select-none w-8 text-center shrink-0">4</span><div class="min-w-0"><div class="font-semibold text-gray-900 group-hover:text-green-600 transition-colors">Les verbes irréguliers</div><div class="text-sm text-gray-500 mt-1">sein, haben, werden - les trois verbes incontournables.</div></div><span class="ml-auto text-gray-300 group-hover:text-green-400 transition-colors shrink-0">→</span></a><a href="./pronoms-personnels" class="group flex items-start gap-5 p-5 rounded-xl border border-gray-200 hover:border-green-500 hover:shadow-md transition-all duration-200 no-underline"><span class="text-3xl font-black text-gray-300 group-hover:text-green-200 transition-colors select-none w-8 text-center shrink-0">5</span><div class="min-w-0"><div class="font-semibold text-gray-900 group-hover:text-green-600 transition-colors">Les pronoms personnels</div><div class="text-sm text-gray-500 mt-1">ich, du, er, sie, es, wir, ihr, sie, Sie - et la distinction tu/vous.</div></div><span class="ml-auto text-gray-300 group-hover:text-green-400 transition-colors shrink-0">→</span></a><a href="./negation" class="group flex items-start gap-5 p-5 rounded-xl border border-gray-200 hover:border-green-500 hover:shadow-md transition-all duration-200 no-underline"><span class="text-3xl font-black text-gray-300 group-hover:text-green-200 transition-colors select-none w-8 text-center shrink-0">6</span><div class="min-w-0"><div class="font-semibold text-gray-900 group-hover:text-green-600 transition-colors">La négation</div><div class="text-sm text-gray-500 mt-1">Quand utiliser nicht et quand utiliser kein.</div></div><span class="ml-auto text-gray-300 group-hover:text-green-400 transition-colors shrink-0">→</span></a></div>',7)])])}const m=r(n,[["render",a]]);export{g as __pageData,m as default};
